import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import '../styles/Auth.css';
import logo from '../assets/logo.png';

const Register = () => {
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    username: '',
    clientCode: '',
    password: ''
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Handle registration logic here
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <div className="logo-container">
          <img src={logo} alt="Loyal String RFID" />
          <h1>RFID Dashboard</h1>
          <p>Register to access the dashboard</p>
        </div>
        
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label className="form-label">Username</label>
            <div className="input-icon-wrapper">
              <i className="input-icon fas fa-user"></i>
              <input
                type="text"
                name="username"
                className="form-control input-with-icon"
                value={formData.username}
                onChange={handleChange}
                placeholder="Enter your username"
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label className="form-label">Client Code</label>
            <div className="input-icon-wrapper">
              <i className="input-icon fas fa-building"></i>
              <input
                type="text"
                name="clientCode"
                className="form-control input-with-icon"
                value={formData.clientCode}
                onChange={handleChange}
                placeholder="Enter your client code"
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label className="form-label">Password</label>
            <div className="input-icon-wrapper">
              <i className="input-icon fas fa-lock"></i>
              <input
                type={showPassword ? "text" : "password"}
                name="password"
                className="form-control input-with-icon"
                value={formData.password}
                onChange={handleChange}
                placeholder="Enter your password"
                required
              />
              <i
                className={`password-toggle fas ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}
                onClick={() => setShowPassword(!showPassword)}
              ></i>
            </div>
          </div>

          <div className="password-requirements">
            <p style={{ marginBottom: '0.5rem', fontWeight: '500' }}>Password must contain:</p>
            <ul>
              <li>At least one uppercase letter</li>
              <li>At least one number</li>
              <li>At least one special character</li>
            </ul>
          </div>

          <button type="submit" className="auth-button">
            Register
          </button>
        </form>

        <Link to="/login" className="auth-link">
          Already have an account? Login now
        </Link>
      </div>
    </div>
  );
};

export default Register;
